class Solution:
    def getSmallestString(self, s: str, k: int) -> str:
        t = list(s)
        n = len(s)

        for i in range(n):
            original_char = s[i]
            for c in range(ord('a'), ord(original_char) + 1):
                cost = (ord(original_char) - ord(c)) % 26
                if cost <= k:
                    t[i] = chr(c)
                    k -= cost
                    break

        return ''.join(t)
